/**
 * Builds a fake `claude` binary that records its argv + env to a JSON file
 * and exits 0. Used as a stand-in for the real claude binary in tests.
 *
 * Usage:
 *   node build-fake-bin.mjs <output-path>
 */

import { writeFileSync } from "node:fs"
import { argv } from "node:process"

const out = argv[2]
if (!out) {
  console.error("usage: node build-fake-bin.mjs <output>")
  process.exit(2)
}

const script = `#!/usr/bin/env node
// Auto-generated by build-fake-bin.mjs — fake claude binary for tests.
import { writeFileSync, appendFileSync } from "node:fs";
import { argv, env, exit } from "node:process";

const recordPath = process.env.CW_TEST_FAKE_CLAUDE_RECORD;
const record = {
  argv: [...argv],
  env: { ...env },
  cwd: process.cwd(),
  pid: process.pid,
  exitCode: parseInt(process.env.CW_TEST_FAKE_CLAUDE_EXIT ?? "0", 10),
};

if (recordPath) {
  try {
    writeFileSync(recordPath, JSON.stringify(record, null, 2));
  } catch (e) {
    console.error("fake-claude-bin: failed to write record:", e);
    exit(2);
  }
}
exit(record.exitCode);
`

writeFileSync(out, script, { mode: 0o755 })
console.log(`fake-claude-bin written to ${out}`)
